previewCss:
.darma-loader-uiverse-boxing-label-loader {
  display: flex;
  align-items: center;
  justify-content: center;
}
.darma-loader-uiverse-boxing-label-loader__wrapper {
  width: 180px;
  height: 50px;
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 2;
}
.darma-loader-uiverse-boxing-label-loader__text {
  z-index: 3;
  font-family: Whitney, -apple-system, Helvetica;
  letter-spacing: 1px;
  font-weight: 700;
  font-size: 20px;
  color: white;
  filter: drop-shadow(2px 2px 0px #ff9e02);
}
.darma-loader-uiverse-boxing-label-loader__box {
  width: 100%;
  height: 100%;
  background-color: #ef5d2e;
  position: absolute;
  z-index: 2;
  display: flex;
  align-items: center;
  justify-content: center;
  animation: darma-loader-uiverse-boxing-label-loader-loading ease-in-out 0.9s infinite alternate-reverse;
}
@keyframes darma-loader-uiverse-boxing-label-loader-loading {
  0% {
    transform: translateX(-20px);
  }
  100% {
    transform: translateX(20px);
  }
}
.darma-loader-uiverse-boxing-label-loader__box::before {
  content: "";
  width: 20px;
  height: 170%;
  background-color: #ff9d0089;
  position: absolute;
  z-index: 1;
  animation: darma-loader-uiverse-boxing-label-loader-loading2 ease-in-out 0.9s infinite alternate-reverse;
}
@keyframes darma-loader-uiverse-boxing-label-loader-loading2 {
  0% {
    transform: translateX(-50px);
  }
  100% {
    transform: translateX(50px);
  }
}

